#include <stdio.h>
#include <math.h>

int main() {
    int n;
    double sum = 0.0;

    printf("Enter the value of n: ");
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        double numerator = 2 * i + 1;
        double denominator = i * i - 1;
        sum += pow(-1, i + 1) * numerator / denominator;
    }

    printf("The sum of the series is: %.6f\n", sum);

    return 0;
}

#include <stdio.h>

int main() {
    int n;

    // Read integer n from the user
    printf("Enter an integer n (1 to 10): ");
    scanf("%d", &n);

    // Generate and print the triangle pattern
    for (int i = 1; i <= n; i++) {
        // Print leading spaces
        for (int j = n - i; j > 0; j--) {
            printf(" ");
        }

        // Print digits
        for (int k = 0; k < i; k++) {
            printf("%d", i);
        }

        // Move to the next line
        printf("\n");
    }

    return 0;
}
